/**
 * Sign a new access token for a user.
 */
function signAccessToken(user) {
  const payload = {
    sub: user.id,
    email: user.email,
    roles: user.roles || [],
    tokenVersion: user.tokenVersion || 1,
  };

  return jwt.sign(payload, config.jwt.secret, {
    algorithm: config.jwt.allowedAlgorithms[0],
    expiresIn: config.jwt.accessTokenTTL,
    issuer: config.jwt.issuer,
    audience: config.jwt.audience,
    jwtid: crypto.randomUUID(), // Unique token ID for audit trails
  });
}

/**
 * Sign a refresh token for a user.
 */
function signRefreshToken(user) {
  const payload = {
    sub: user.id,
    tokenVersion: user.tokenVersion || 1,
    type: 'refresh',
  };

  return jwt.sign(payload, config.jwt.secret, {
    algorithm: config.jwt.allowedAlgorithms[0],
    expiresIn: config.jwt.refreshTokenTTL,
    issuer: config.jwt.issuer,
    audience: config.jwt.audience,
    jwtid: crypto.randomUUID(),
  });
}

/**
 * Verify and decode a JWT. Returns the decoded payload or throws.
 */
function verifyToken(token, expectedType = 'access') {
  // `algorithms` is the allowlist — jsonwebtoken will reject tokens
  // signed with any algorithm not in this list, including "none"
  const decoded = jwt.verify(token, config.jwt.secret, {
    algorithms: config.jwt.allowedAlgorithms,
    issuer: config.jwt.issuer,
    audience: config.jwt.audience,
    // Require these claims to be present
    complete: false,
  });

  // Verify token type for refresh tokens
  if (expectedType === 'refresh' && decoded.type !== 'refresh') {
    throw new Error('Invalid token type: expected refresh token');
  }

  if (expectedType === 'access' && decoded.type === 'refresh') {
    throw new Error('Invalid token type: refresh token used as access token');
  }

  // Ensure required claims exist
  if (!decoded.sub) {
    throw new Error('Token missing required "sub" claim');
  }

  // Check token version against the in-memory revocation cache
  // This is O(1) — no database call
  if (decoded.tokenVersion !== undefined) {
    if (tokenVersionCache.isRevoked(decoded.sub, decoded.tokenVersion)) {
      throw new Error('Token has been revoked');
    }
  }

  return decoded;
}

