/**
 * Core authentication middleware.
 * Extracts the Bearer token, verifies signature + claims, and attaches
 * user info to req.user.
 * 
 * Performance characteristics:
 *   - Pure CPU work (signature verification + JSON parse)
 *   - No I/O, no database calls, no network calls
 *   - O(1) revocation check against in-memory cache
 */
function authenticate(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    return res.status(401).json({
      error: 'Authentication required',
      code: 'MISSING_AUTH_HEADER',
    });
  }

  // Expect "Bearer <token>"
  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return res.status(401).json({
      error: 'Invalid authorization format. Expected: Bearer <token>',
      code: 'INVALID_AUTH_FORMAT',
    });
  }

  const token = parts[1];

  // Basic sanity check — reject obviously malformed tokens early
  // (avoids unnecessary work in the jwt library)
  if (token.length > 4096) {
    return res.status(401).json({
      error: 'Token too large',
      code: 'TOKEN_TOO_LARGE',
    });
  }

  try {
    const decoded = verifyToken(token, 'access');

    // Attach user information to the request object
    req.user = {
      id: decoded.sub,
      email: decoded.email,
      roles: decoded.roles || [],
      tokenVersion: decoded.tokenVersion,
      jti: decoded.jti,       // JWT ID for audit logging
      iat: decoded.iat,       // Issued at
      exp: decoded.exp,       // Expiration
    };

    next();
  } catch (err) {
    // Map specific JWT errors to appropriate responses
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({
        error: 'Token has expired',
        code: 'TOKEN_EXPIRED',
        expiredAt: err.expiredAt,
      });
    }

    if (err.name === 'JsonWebTokenError') {
      return res.status(401).json({
        error: 'Invalid token',
        code: 'INVALID_TOKEN',
      });
    }

    if (err.name === 'NotBeforeError') {
      return res.status(401).json({
        error: 'Token not yet active',
        code: 'TOKEN_NOT_ACTIVE',
      });
    }

    // Revoked token or other custom errors
    return res.status(401).json({
      error: 'Authentication failed',
      code: 'AUTH_FAILED',
    });
  }
}

/**
 * Role-based authorization middleware factory.
 * Use after authenticate middleware.
 * 
 * Example: app.get('/admin', authenticate, authorize('admin'), handler)
 */
function authorize(...requiredRoles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({
        error: 'Authentication required',
        code: 'NOT_AUTHENTICATED',
      });
    }

    if (requiredRoles.length === 0) {
      return next();
    }

    const userRoles = new Set(req.user.roles);
    const hasRole = requiredRoles.some((role) => userRoles.has(role));

    if (!hasRole) {
      return res.status(403).json({
        error: 'Insufficient permissions',
        code: 'FORBIDDEN',
        required: requiredRoles,
      });
    }

    next();
  };
}

/**
 * Optional authentication middleware.
 * Attaches user info if a valid token is present, but doesn't reject
 * requests without tokens. Useful for endpoints that behave differently
 * for authenticated vs. anonymous users.
 */
function optionalAuthenticate(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    req.user = null;
    return next();
  }

  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    req.user = null;
    return next();
  }

  try {
    const decoded = verifyToken(parts[1], 'access');
    req.user = {
      id: decoded.sub,
      email: decoded.email,
      roles: decoded.roles || [],
      tokenVersion: decoded.tokenVersion,
      jti: decoded.jti,
      iat: decoded.iat,
      exp: decoded.exp,
    };
  } catch {
    req.user = null;
  }

  next();
}

